package httptransport

import "net/http"

const openAPISpecYAML = "openapi: 3.0.3\ninfo:\n  title: SakeOfHer API\n  version: 0.2.0\n  description: |\n    API проекта SakeOfHer для сайтного MVP без механики платежей.\n\n    Сейчас реализованы:\n    - health-check;\n    - получение тарифов;\n    - создание/получение пользователя по Telegram ID;\n    - покупка подписки с ручным лимитом трафика;\n    - продление подписки с автоматическим подтягиванием прошлого лимита;\n    - публичное получение подписки по public_token.\nservers:\n  - url: http://localhost:8080\n    description: Local API\n  - url: https://api.example.com\n    description: Production API placeholder\ntags:\n  - name: System\n    description: Системные endpoint'ы\n  - name: Tariffs\n    description: Тарифы\n  - name: Site subscriptions\n    description: Сайтная механика покупки и продления подписок без оплат\n  - name: Public subscriptions\n    description: Публичное получение подписки по токену\n  - name: Bot internal\n    description: Внутренние endpoint'ы для будущего Telegram-бота\npaths:\n  /api/v1/health:\n    get:\n      tags: [System]\n      summary: Проверить, что API работает\n      operationId: healthCheck\n      responses:\n        '200':\n          description: API работает\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/HealthResponse'\n              example:\n                status: ok\n\n  /api/v1/tariffs:\n    get:\n      tags: [Tariffs]\n      summary: Получить активные тарифы с ценами\n      operationId: listTariffs\n      responses:\n        '200':\n          description: Список активных тарифов\n          content:\n            application/json:\n              schema:\n                type: array\n                items:\n                  $ref: '#/components/schemas/TariffWithPrices'\n        '500':\n          $ref: '#/components/responses/InternalServerError'\n\n  /api/v1/public/subscriptions/{public_token}:\n    get:\n      tags: [Public subscriptions]\n      summary: Получить публичную информацию о подписке\n      operationId: getPublicSubscription\n      parameters:\n        - name: public_token\n          in: path\n          required: true\n          description: Публичный токен подписки\n          schema:\n            type: string\n          example: 6d1f4e9c2a7b4d1fb9e0f1a2c3d4e5f6\n      responses:\n        '200':\n          description: Данные подписки\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/PublicSubscription'\n        '404':\n          $ref: '#/components/responses/NotFound'\n        '500':\n          $ref: '#/components/responses/InternalServerError'\n\n  /api/v1/bot/start:\n    post:\n      tags: [Bot internal]\n      summary: Создать или получить пользователя по Telegram данным\n      operationId: botStart\n      requestBody:\n        required: true\n        content:\n          application/json:\n            schema:\n              $ref: '#/components/schemas/TelegramUserInput'\n            example:\n              telegram_id: 123456\n              telegram_username: test_user\n              telegram_first_name: Test\n              telegram_last_name: User\n              language_code: ru\n      responses:\n        '200':\n          description: Пользователь создан или найден\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/User'\n        '400':\n          $ref: '#/components/responses/BadRequest'\n        '500':\n          $ref: '#/components/responses/InternalServerError'\n\n  /api/v1/bot/users/{telegram_id}/subscription:\n    get:\n      tags: [Bot internal]\n      summary: Получить активную подписку пользователя по Telegram ID\n      operationId: getBotUserSubscription\n      parameters:\n        - name: telegram_id\n          in: path\n          required: true\n          schema:\n            type: integer\n            format: int64\n            minimum: 1\n          example: 123456\n      responses:\n        '200':\n          description: Активная подписка пользователя\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/PublicSubscription'\n        '400':\n          $ref: '#/components/responses/BadRequest'\n        '404':\n          $ref: '#/components/responses/NotFound'\n        '500':\n          $ref: '#/components/responses/InternalServerError'\n\n  /api/v1/site/subscriptions/purchase:\n    post:\n      tags: [Site subscriptions]\n      summary: Купить подписку без платежей с ручным лимитом трафика\n      description: |\n        Сайтный MVP endpoint без реальной оплаты.\n\n        При покупке лимит трафика передаётся вручную через `traffic_limit_gb`.\n        Если у пользователя уже есть активная подписка, срок суммируется.\n        Новый лимит трафика берётся из запроса.\n      operationId: purchaseSubscriptionFromSite\n      requestBody:\n        required: true\n        content:\n          application/json:\n            schema:\n              $ref: '#/components/schemas/SitePurchaseInput'\n            example:\n              telegram_id: 123456\n              telegram_username: test_user\n              telegram_first_name: Test\n              telegram_last_name: User\n              language_code: ru\n              alias: client-001\n              tariff_id: 1\n              traffic_limit_gb: 500\n      responses:\n        '201':\n          description: Подписка создана или продлена\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/PublicSubscription'\n        '400':\n          $ref: '#/components/responses/BadRequest'\n        '404':\n          $ref: '#/components/responses/NotFound'\n        '500':\n          $ref: '#/components/responses/InternalServerError'\n\n  /api/v1/site/subscriptions/renew:\n    post:\n      tags: [Site subscriptions]\n      summary: Продлить подписку без указания лимита трафика\n      description: |\n        При продлении лимит трафика не передаётся.\n        Backend автоматически берёт лимит из текущей или последней подписки.\n        Срок подписки суммируется: новая дата окончания считается от текущего `expires_at`, если подписка ещё активна.\n      operationId: renewSubscriptionFromSite\n      requestBody:\n        required: true\n        content:\n          application/json:\n            schema:\n              $ref: '#/components/schemas/SiteRenewInput'\n            examples:\n              by_public_token:\n                summary: Продление по public_token\n                value:\n                  public_token: 6d1f4e9c2a7b4d1fb9e0f1a2c3d4e5f6\n              by_telegram_id:\n                summary: Продление по telegram_id\n                value:\n                  telegram_id: 123456\n      responses:\n        '200':\n          description: Подписка продлена\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/PublicSubscription'\n        '400':\n          $ref: '#/components/responses/BadRequest'\n        '404':\n          $ref: '#/components/responses/NotFound'\n        '500':\n          $ref: '#/components/responses/InternalServerError'\n\ncomponents:\n  responses:\n    BadRequest:\n      description: Ошибка валидации или некорректный запрос\n      content:\n        application/json:\n          schema:\n            $ref: '#/components/schemas/ErrorResponse'\n          example:\n            error: invalid input\n    NotFound:\n      description: Сущность не найдена\n      content:\n        application/json:\n          schema:\n            $ref: '#/components/schemas/ErrorResponse'\n          example:\n            error: not found\n    InternalServerError:\n      description: Внутренняя ошибка сервера\n      content:\n        application/json:\n          schema:\n            $ref: '#/components/schemas/ErrorResponse'\n          example:\n            error: internal server error\n\n  schemas:\n    HealthResponse:\n      type: object\n      required: [status]\n      properties:\n        status:\n          type: string\n          example: ok\n\n    ErrorResponse:\n      type: object\n      required: [error]\n      properties:\n        error:\n          type: string\n          example: invalid input\n\n    UserStatus:\n      type: string\n      enum: [active, blocked, deleted]\n      example: active\n\n    RemnaStatus:\n      type: string\n      enum: [not_created, active, disabled, deleted]\n      example: not_created\n\n    SubscriptionStatus:\n      type: string\n      enum: [active, expired, cancelled]\n      example: active\n\n    PeriodStatus:\n      type: string\n      enum: [active, traffic_exhausted, finished]\n      example: active\n\n    PaymentProvider:\n      type: string\n      enum: [telegram_stars, tribute, crypto_bot]\n      example: tribute\n\n    PaymentMethod:\n      type: string\n      enum: [stars, rub, crypto]\n      example: rub\n\n    User:\n      type: object\n      required:\n        - id\n        - telegram_id\n        - status\n        - remna_status\n        - created_at\n        - updated_at\n      properties:\n        id:\n          type: integer\n          format: int64\n          example: 1\n        telegram_id:\n          type: integer\n          format: int64\n          example: 123456\n        telegram_username:\n          type: string\n          nullable: true\n          example: test_user\n        telegram_first_name:\n          type: string\n          nullable: true\n          example: Test\n        telegram_last_name:\n          type: string\n          nullable: true\n          example: User\n        language_code:\n          type: string\n          nullable: true\n          example: ru\n        alias:\n          type: string\n          nullable: true\n          example: client-001\n        remna_uuid:\n          type: string\n          nullable: true\n          example: 5e8f4c33-7a31-4d79-8c4a-2c1847ec2f89\n        remna_username:\n          type: string\n          nullable: true\n          example: tg_123456\n        subscription_url:\n          type: string\n          nullable: true\n          example: https://panel.example.com/sub/example\n        status:\n          $ref: '#/components/schemas/UserStatus'\n        remna_status:\n          $ref: '#/components/schemas/RemnaStatus'\n        disabled_at:\n          type: string\n          format: date-time\n          nullable: true\n        delete_after:\n          type: string\n          format: date-time\n          nullable: true\n        deleted_at:\n          type: string\n          format: date-time\n          nullable: true\n        last_seen_at:\n          type: string\n          format: date-time\n          nullable: true\n        created_at:\n          type: string\n          format: date-time\n        updated_at:\n          type: string\n          format: date-time\n\n    TelegramUserInput:\n      type: object\n      required: [telegram_id]\n      properties:\n        telegram_id:\n          type: integer\n          format: int64\n          minimum: 1\n          example: 123456\n        telegram_username:\n          type: string\n          nullable: true\n          example: test_user\n        telegram_first_name:\n          type: string\n          nullable: true\n          example: Test\n        telegram_last_name:\n          type: string\n          nullable: true\n          example: User\n        language_code:\n          type: string\n          nullable: true\n          example: ru\n\n    Tariff:\n      type: object\n      required:\n        - id\n        - code\n        - title\n        - duration_days\n        - period_days\n        - traffic_limit_bytes\n        - is_active\n        - sort_order\n        - created_at\n        - updated_at\n      properties:\n        id:\n          type: integer\n          format: int64\n          example: 1\n        code:\n          type: string\n          example: vpn_1m_300gb\n        title:\n          type: string\n          example: 1 месяц\n        description:\n          type: string\n          nullable: true\n          example: VPN на 1 месяц\n        duration_days:\n          type: integer\n          example: 30\n        period_days:\n          type: integer\n          example: 30\n        traffic_limit_bytes:\n          type: integer\n          format: int64\n          example: 322122547200\n        is_active:\n          type: boolean\n          example: true\n        sort_order:\n          type: integer\n          example: 10\n        created_at:\n          type: string\n          format: date-time\n        updated_at:\n          type: string\n          format: date-time\n\n    TariffPrice:\n      type: object\n      required:\n        - id\n        - tariff_id\n        - provider\n        - payment_method\n        - currency\n        - accepted_assets\n        - is_active\n        - sort_order\n        - created_at\n        - updated_at\n      properties:\n        id:\n          type: integer\n          format: int64\n          example: 1\n        tariff_id:\n          type: integer\n          format: int64\n          example: 1\n        provider:\n          $ref: '#/components/schemas/PaymentProvider'\n        payment_method:\n          $ref: '#/components/schemas/PaymentMethod'\n        currency:\n          type: string\n          example: RUB\n        amount_minor:\n          type: integer\n          format: int64\n          nullable: true\n          example: 7000\n        stars_amount:\n          type: integer\n          format: int64\n          nullable: true\n          example: 50\n        accepted_assets:\n          type: array\n          items:\n            type: string\n          example: [USDT, TON]\n        is_active:\n          type: boolean\n          example: true\n        sort_order:\n          type: integer\n          example: 10\n        created_at:\n          type: string\n          format: date-time\n        updated_at:\n          type: string\n          format: date-time\n\n    TariffWithPrices:\n      allOf:\n        - $ref: '#/components/schemas/Tariff'\n        - type: object\n          required: [prices]\n          properties:\n            prices:\n              type: array\n              items:\n                $ref: '#/components/schemas/TariffPrice'\n\n    Subscription:\n      type: object\n      required:\n        - id\n        - user_id\n        - status\n        - started_at\n        - expires_at\n        - current_period_start\n        - current_period_end\n        - traffic_limit_bytes\n        - traffic_used_bytes\n        - period_status\n        - public_token\n        - notified_3_days\n        - notified_1_day\n        - notified_expired\n        - traffic_80_notified\n        - traffic_95_notified\n        - traffic_exhausted_notified\n        - created_at\n        - updated_at\n      properties:\n        id:\n          type: integer\n          format: int64\n          example: 1\n        user_id:\n          type: integer\n          format: int64\n          example: 1\n        last_payment_id:\n          type: integer\n          format: int64\n          nullable: true\n        tariff_id:\n          type: integer\n          format: int64\n          nullable: true\n          example: 1\n        status:\n          $ref: '#/components/schemas/SubscriptionStatus'\n        started_at:\n          type: string\n          format: date-time\n        expires_at:\n          type: string\n          format: date-time\n        current_period_start:\n          type: string\n          format: date-time\n        current_period_end:\n          type: string\n          format: date-time\n        traffic_limit_bytes:\n          type: integer\n          format: int64\n          example: 536870912000\n        traffic_used_bytes:\n          type: integer\n          format: int64\n          example: 0\n        period_status:\n          $ref: '#/components/schemas/PeriodStatus'\n        public_token:\n          type: string\n          example: 6d1f4e9c2a7b4d1fb9e0f1a2c3d4e5f6\n        last_remna_check_at:\n          type: string\n          format: date-time\n          nullable: true\n        last_expire_notification_at:\n          type: string\n          format: date-time\n          nullable: true\n        last_traffic_notification_at:\n          type: string\n          format: date-time\n          nullable: true\n        notified_3_days:\n          type: boolean\n          example: false\n        notified_1_day:\n          type: boolean\n          example: false\n        notified_expired:\n          type: boolean\n          example: false\n        traffic_80_notified:\n          type: boolean\n          example: false\n        traffic_95_notified:\n          type: boolean\n          example: false\n        traffic_exhausted_notified:\n          type: boolean\n          example: false\n        created_at:\n          type: string\n          format: date-time\n        updated_at:\n          type: string\n          format: date-time\n\n    PublicSubscription:\n      type: object\n      required: [subscription, user, tariff]\n      properties:\n        subscription:\n          $ref: '#/components/schemas/Subscription'\n        user:\n          $ref: '#/components/schemas/User'\n        tariff:\n          $ref: '#/components/schemas/Tariff'\n        subscription_url:\n          type: string\n          nullable: true\n          example: https://panel.example.com/sub/example\n\n    SitePurchaseInput:\n      type: object\n      required:\n        - telegram_id\n        - tariff_id\n        - traffic_limit_gb\n      properties:\n        telegram_id:\n          type: integer\n          format: int64\n          minimum: 1\n          example: 123456\n        telegram_username:\n          type: string\n          nullable: true\n          example: test_user\n        telegram_first_name:\n          type: string\n          nullable: true\n          example: Test\n        telegram_last_name:\n          type: string\n          nullable: true\n          example: User\n        language_code:\n          type: string\n          nullable: true\n          example: ru\n        alias:\n          type: string\n          nullable: true\n          example: client-001\n        tariff_id:\n          type: integer\n          format: int64\n          minimum: 1\n          example: 1\n        traffic_limit_gb:\n          type: integer\n          format: int64\n          minimum: 1\n          example: 500\n\n    SiteRenewInput:\n      type: object\n      description: Нужно передать либо public_token, либо telegram_id. Лимит трафика не передаётся и подтягивается автоматически.\n      properties:\n        telegram_id:\n          type: integer\n          format: int64\n          minimum: 1\n          example: 123456\n        public_token:\n          type: string\n          example: 6d1f4e9c2a7b4d1fb9e0f1a2c3d4e5f6\n        tariff_id:\n          type: integer\n          format: int64\n          nullable: true\n          example: 1\n"

